db_lock = threading.Lock()

# ── Rate limiting para login ─────────────────────────────────────────
_login_attempts: dict = {}  # {ip: [timestamp, ...]}
_login_lock = threading.Lock()
_ia_calls: dict = {}  # {user_id_or_ip: [timestamp, ...]} para rate limit IA
_ia_lock   = threading.Lock()
IA_MAX_CALLS = 30   # llamadas por ventana
IA_WINDOW    = 3600 # 1 hora

def _check_ia_limit(key: str) -> bool:
    import time
    now = time.time()
    with _ia_lock:
        calls = [t for t in _ia_calls.get(key, []) if now - t < IA_WINDOW]
        _ia_calls[key] = calls
        if len(calls) >= IA_MAX_CALLS: return False
        _ia_calls[key].append(now)
        return True
LOGIN_MAX_ATTEMPTS = 5
LOGIN_WINDOW_SECS  = 900  # 15 minutos

def _check_rate_limit(ip: str) -> bool:
    """Retorna True si la IP puede intentar login, False si está bloqueada."""
    import time
    now = time.time()
    with _login_lock:
        attempts = _login_attempts.get(ip, [])
        # Limpiar intentos fuera de la ventana
        attempts = [t for t in attempts if now - t < LOGIN_WINDOW_SECS]
        _login_attempts[ip] = attempts
        return len(attempts) < LOGIN_MAX_ATTEMPTS

def _register_login_attempt(ip: str):
    """Registra un intento fallido de login."""
    import time
    with _login_lock:
        _login_attempts.setdefault(ip, []).append(time.time())

def _reset_login_attempts(ip: str):
    """Limpia intentos tras login exitoso."""
    with _login_lock:
        _login_attempts.pop(ip, None)

def _init_sqlite(skip_seed=False):
    """Create SQLite DB. Si skip_seed=True (Postgres disponible), no hace seed
    con datos demo — SQLite solo actúa como caché temporal."""
    global DB_SQLITE
    try:
        DB_SQLITE.parent.mkdir(parents=True, exist_ok=True)
        conn = sqlite3.connect(str(DB_SQLITE), timeout=15)
    except (OSError, PermissionError) as e:
        fallback = pathlib.Path('/tmp/imbio.db')
        print(f"[START] No se pudo usar {DB_SQLITE}: {e}. Usando {fallback}", flush=True)
        DB_SQLITE = fallback
        conn = sqlite3.connect(str(DB_SQLITE), timeout=15)
    conn.execute("""CREATE TABLE IF NOT EXISTS store (
        id   INTEGER PRIMARY KEY,
        data TEXT NOT NULL
    )""")
    conn.commit()
    row = conn.execute("SELECT data FROM store WHERE id=1").fetchone()
    if not row and skip_seed:
        # Postgres está activo — poner placeholder vacío en SQLite, no demos
        placeholder = json.dumps({"reports":[],"users":[],"actas":[],"assignments":[]}, ensure_ascii=False)
        conn.execute("INSERT INTO store(id,data) VALUES(1,?)", (placeholder,))
        conn.commit()
        conn.close()
        print("[START] SQLite inicializado como caché (datos en Postgres)", flush=True)
        return
    if not row:
        # Orden de prioridad para el seed inicial:
        # 1. db_backup.json  — copia automática del último estado real
        # 2. db.json         — seed manual o datos exportados
        # 3. Datos mínimos   — solo usuarios, sin reportes demo
        backup_path = DB_SQLITE.parent / 'db_backup.json'
        if backup_path.exists() and backup_path.stat().st_size > 100:
            seed = backup_path.read_text(encoding='utf-8')
            print("[START] ✅ Restaurando desde db_backup.json", flush=True)
        elif DB_FILE.exists():
            seed = DB_FILE.read_text(encoding='utf-8')
            print("[START] Seed desde db.json", flush=True)
        else:
            seed = json.dumps({
                "reports": [], "assignments": [], "users": [
                    {"id":1,"username":"admin","password": hashlib.sha256(b"admin123").hexdigest(),"nombre":"Administrador IMBIO","rol":"admin","activo":True},
                    {"id":2,"username":"operador","password": hashlib.sha256(b"operador123").hexdigest(),"nombre":"Operador IMBIO","rol":"operador","activo":True},
                    {"id":3,"username":"inspector01","password": hashlib.sha256(b"inspector123").hexdigest(),"nombre":"Inspector Campo 01","rol":"inspector","brigada":"Brigada 1","activo":True}
                ], "actas": [], "establecimientos": [], "verificaciones": []
            }, ensure_ascii=False)
            print("[START] DB nueva — sin datos demo. Configura DB_PATH para persistencia.", flush=True)
        conn.execute("INSERT INTO store(id,data) VALUES(1,?)", (seed,))
        conn.commit()
    conn.close()

# ── DENUE Seed ──────────────────────────────────────────────────────────────
def _load_denue_seed():
    """Carga establecimientos del DENUE INEGI si el padrón está vacío."""
    try:
        if not _DENUE_SEED_PATH.exists():
            print('[DENUE] Archivo seed no encontrado:', _DENUE_SEED_PATH)
            return 0
        db = read_db()
        existing = db.get('establecimientos', [])
        if len(existing) > 0:
            print(f'[DENUE] Padrón ya tiene {len(existing)} registros, seed omitido.')
            return 0
        with open(_DENUE_SEED_PATH, 'r', encoding='utf-8') as f:
            denue_data = json.load(f)
        # Asegurarse de que cada registro tenga los campos mínimos
        for i, e in enumerate(denue_data, 1):
            e.setdefault('id', i)
            e.setdefault('estado_cumplimiento', 'sin_verificar')
            e.setdefault('permisos', [])
            e.setdefault('fuente', 'DENUE_INEGI_2026')
        db['establecimientos'] = denue_data
        write_db(db)
        print(f'[DENUE] ✅ Seed cargado: {len(denue_data)} establecimientos de Pabellón de Arteaga.')
        return len(denue_data)
    except Exception as e:
        print(f'[DENUE] ❌ Error en seed: {e}')
        return 0

def read_db():
    # ── Si Postgres está configurado, ES la fuente de verdad — SIEMPRE ────
    if _PG_URL and _PG_AVAILABLE:
        pg = _pg_conn()
        if pg:
            try:
                with pg.cursor() as cur:
                    cur.execute("SELECT data FROM imbio_store WHERE id=1")
                    row = cur.fetchone()
                pg.close()
                if row:
                    db = json.loads(row[0])
                else:
                    db = _migrar_sqlite_a_pg()
            except Exception as e:
                print(f'[PG] read_db error: {e} — fallback a SQLite', flush=True)
                try: pg.close()
                except: pass
                db = _read_sqlite()
        else:
            print('[PG] Sin conexión — usando SQLite', flush=True)
            db = _read_sqlite()
    else:
        db = _read_sqlite()
    db = json.loads(json.dumps(db))  # copia limpia
    # Migración automática (fuera del lock para no bloquear)
    changed = False
    if 'actas' not in db:
        db['actas'] = []; changed = True
    if 'establecimientos' not in db:
        db['establecimientos'] = []; changed = True
    if 'verificaciones' not in db:
        db['verificaciones'] = []; changed = True
    if 'historial_estados' not in db:
        db['historial_estados'] = []; changed = True
    if 'expedientes' not in db:
        db['expedientes'] = []
        for rep in db.get('reports', []):
            if not rep.get('expediente'):
                exp_num = generate_expediente(db)
                rep['expediente'] = exp_num
                db['expedientes'].append({
                    'id': len(db['expedientes']) + 1,
                    'numero': exp_num,
                    'report_id': rep['id'],
                    'folio_reporte': rep.get('folio', ''),
                    'fecha_apertura': rep.get('fecha_creacion', now_iso()),
                    'estado': rep.get('estado', 'reportado'),
                })
        changed = True
    for idx_u, u in enumerate(db.get('users', [])):
        if 'id' not in u:
            u['id'] = idx_u + 1; changed = True
    if changed:
        write_db(db)
    return db

def _read_sqlite():
    """Lee desde SQLite como fallback."""
    with db_lock:
        conn = sqlite3.connect(str(DB_SQLITE), timeout=15)
        row = conn.execute("SELECT data FROM store WHERE id=1").fetchone()
        conn.close()
    return json.loads(row[0]) if row else {}

def _migrar_sqlite_a_pg():
    """Primera vez: copia datos de SQLite a Postgres y devuelve el db."""
    try:
        db = _read_sqlite()
        if db:
            _write_pg(db)
            print('[PG] ✅ Datos migrados desde SQLite a Postgres', flush=True)
        return db
    except Exception as e:
        print(f'[PG] Error migración: {e}', flush=True)
        return {}

def _write_pg(db):
    """Escribe en Postgres (INSERT o UPDATE)."""
    pg = _pg_conn()
    if not pg:
        return False
    try:
        serialized = json.dumps(db, ensure_ascii=False)
        with pg.cursor() as cur:
            cur.execute("""
                INSERT INTO imbio_store(id, data) VALUES(1, %s)
                ON CONFLICT(id) DO UPDATE SET data = EXCLUDED.data
            """, (serialized,))
        pg.commit()
        pg.close()
        return True
    except Exception as e:
        print(f'[PG] write error: {e}', flush=True)
        try: pg.close()
        except: pass
        return False

def write_db(db):
    serialized = json.dumps(db, ensure_ascii=False)
    # ── Escribir en Postgres (fuente principal) ────────────────────────────
    pg_ok = _write_pg(db)
    # ── Escribir en SQLite como backup local ──────────────────────────────
    if not pg_ok:
        with db_lock:
            conn = sqlite3.connect(str(DB_SQLITE), timeout=15)
            conn.execute("UPDATE store SET data=? WHERE id=1", (serialized,))
            conn.commit()
            conn.close()
    # ── Backup JSON en disco ───────────────────────────────────────────────
    try:
        backup_path = DB_SQLITE.parent / 'db_backup.json'
        backup_path.write_text(serialized, encoding='utf-8')
    except Exception:
        pass
    # ── Backup automático en JSON ─────────────────────────────────────────
    # Guarda siempre una copia legible en data/db_backup.json.
    # Si el servidor corre en Railway/Render SIN volumen persistente,
    # este archivo también se perderá al reiniciar — en ese caso configurar
    # la variable de entorno DB_PATH apuntando a un volumen montado:
    #   DB_PATH=/data/imbio.db  (Railway: Settings > Volumes > mount en /data)
    try:
        backup_path = DB_SQLITE.parent / 'db_backup.json'
        backup_path.write_text(serialized, encoding='utf-8')
    except Exception:
        pass  # No fallar si no se puede escribir el backup

def hash_pw(pw):
    return hashlib.sha256(pw.encode()).hexdigest()

def now_iso():
    return datetime.now(timezone.utc).isoformat()

def _calcular_vencimiento(plazo_str: str, fecha_base: str) -> str:
    """Calcula la fecha de vencimiento a partir del plazo.
    Ej: '72 horas', '5 días naturales', '15 días hábiles' -> ISO date
    """
    if not plazo_str or not fecha_base:
        return ''
    try:
        from datetime import datetime as _dt, timedelta as _td, timezone as _tz
        base = _dt.fromisoformat(fecha_base.replace('Z', '+00:00'))
        p = plazo_str.lower()
        if 'hora' in p:
            nums = [int(x) for x in p.split() if x.isdigit()]
            horas = nums[0] if nums else 24
            return (base + _td(hours=horas)).isoformat()
        elif 'día' in p or 'dia' in p or 'natural' in p or 'hábil' in p or 'habil' in p:
            nums = [int(x) for x in p.split() if x.isdigit()]
            dias = nums[0] if nums else 5
            return (base + _td(days=dias)).isoformat()
        return ''
    except Exception:
        return ''

def registrar_cambio_estado(db, report_id, estado_anterior, estado_nuevo, usuario, nota=''):
    """Registra cada cambio de estado en el historial del reporte."""
    if estado_anterior == estado_nuevo:
        return
    hid = (max((h['id'] for h in db.get('historial_estados', [])), default=0)) + 1
    db.setdefault('historial_estados', []).append({
        'id':              hid,
        'report_id':       report_id,
        'estado_anterior': estado_anterior,
        'estado_nuevo':    estado_nuevo,
        'usuario':         usuario,
        'fecha':           now_iso(),
        'nota':            nota,
    })

def generate_folio(db):
    db["folio_counter"] += 1
    return f"IMBIO-2026-{db['folio_counter']:04d}"

def generate_expediente(db):
    """Genera número de expediente formal: EXP-IMBIO-YYYY-NNNN"""
    from datetime import datetime as _dt
    year = _dt.now().year
    key = f"exp_counter_{year}"
    db[key] = db.get(key, 0) + 1
    return f"EXP-IMBIO-{year}-{db[key]:04d}"

# ── JWT minimalista (HMAC-SHA256) ──────────────────────────────────────────
def b64url_encode(data: bytes) -> str:
    return base64.urlsafe_b64encode(data).rstrip(b"=").decode()

def b64url_decode(s: str) -> bytes:
    pad = 4 - len(s) % 4
    return base64.urlsafe_b64decode(s + "=" * (pad % 4))

def jwt_sign(payload: dict) -> str:
    import hmac
    header  = b64url_encode(json.dumps({"alg":"HS256","typ":"JWT"}).encode())
    body    = b64url_encode(json.dumps(payload).encode())
    msg     = f"{header}.{body}".encode()
    sig     = b64url_encode(hmac.new(JWT_SECRET.encode(), msg, hashlib.sha256).digest())
    return f"{header}.{body}.{sig}"

def jwt_verify(token: str):
    import hmac
    try:
        parts = token.split(".")
        if len(parts) != 3: return None
        header, body, sig = parts
        msg      = f"{header}.{body}".encode()
        expected = b64url_encode(hmac.new(JWT_SECRET.encode(), msg, hashlib.sha256).digest())
        if not hmac.compare_digest(sig, expected): return None
        return json.loads(b64url_decode(body))
    except Exception:
        return None

